// Accept Splunk (alert-action, `result`-wrapped) or Elastic (ECS / Kibana alert)
// payloads and emit ONE stable internal schema. Nothing downstream ever
// touches vendor-specific field names again.
const body = $json.body ?? $json;
const raw = body.result ?? body; // Splunk alert actions wrap the event in `result`
const isEcs = !!(raw['kibana.alert.rule.name'] || raw['kibana.alert.uuid'] || raw.event?.kind);

const sevMap = { informational: 1, info: 1, low: 2, medium: 3, high: 4, critical: 5 };
const fallbackId = `gen-${Date.now()}-${Math.random().toString(16).slice(2, 10)}`;

let alert;
if (isEcs) {
  alert = {
    source: 'elastic',
    alert_id: raw['kibana.alert.uuid'] ?? raw._id ?? fallbackId,
    rule_name: raw['kibana.alert.rule.name'] ?? raw.rule?.name ?? 'unknown_rule',
    severity: String(raw['kibana.alert.severity'] ?? raw.event?.severity_label ?? 'medium').toLowerCase(),
    timestamp: raw['@timestamp'] ?? new Date().toISOString(),
    entity: {
      host: raw.host?.name ?? null,
      user: raw.user?.name ?? null,
      src_ip: raw.source?.ip ?? null,
      dest_ip: raw.destination?.ip ?? null,
      process: raw.process?.command_line ?? null,
    },
    description: raw['kibana.alert.reason'] ?? raw.message ?? '',
  };
} else {
  alert = {
    source: 'splunk',
    alert_id: raw.event_id ?? body.sid ?? fallbackId,
    rule_name: body.search_name ?? raw.search_name ?? 'unknown_rule',
    severity: String(raw.severity ?? raw.urgency ?? 'medium').toLowerCase(),
    timestamp: raw._time ?? new Date().toISOString(),
    entity: {
      host: raw.dest_host ?? raw.host ?? null,
      user: raw.user ?? null,
      src_ip: raw.src_ip ?? raw.src ?? null,
      dest_ip: raw.dest_ip ?? raw.dest ?? null,
      process: raw.process ?? null,
    },
    description: raw.signature ?? raw.message ?? '',
  };
}

alert.severity_num = sevMap[alert.severity] ?? 3;
alert.raw = raw;
return [{ json: alert }];

// Defensive parse: LLM output is advisory and may be malformed.
// Anything that fails validation routes to 'needs_review' — never default-allow.
const alert = $('Normalize Alert').item.json;
let out = $json.message?.content ?? $json.output ?? $json.text ?? $json;
if (typeof out === 'string') {
  const m = out.match(/\{[\s\S]*\}/);
  try { out = m ? JSON.parse(m[0]) : null; } catch (e) { out = null; }
}
const allowed = ['true_positive', 'false_positive', 'benign_true_positive'];
const valid = out && typeof out === 'object' && allowed.includes(out.verdict);

return {
  json: {
    ...alert,
    verdict: valid ? out.verdict : 'needs_review',
    confidence: valid ? Math.min(100, Math.max(0, Number(out.confidence) || 0)) : 0,
    rationale: valid ? String(out.rationale ?? '') : 'LLM output failed schema validation — routed to analyst review.',
    mitre_techniques: valid && Array.isArray(out.mitre_techniques) ? out.mitre_techniques : [],
    recommended_actions: valid && Array.isArray(out.recommended_actions) ? out.recommended_actions : [],
  },
};

